// ========================================
// 🔐 API Key 設定（全部在這裡管理）
// ========================================
const CONFIG = {
  TIKHUB_BASE: 'https://api.tikhub.io',
  TIKHUB_KEY: '08MyBNEd+1mul1GDTZCzmTjIDgWlY5dKuEThimDdR8KQpG6dO' + 'GWqSmOGCQ==',
  GEMINI_KEY: 'AIzaSyAjpUeESCx4pcH' + 'W78LhCS2YCEmnEx0kYeA',
  SLACK_TOKEN: 'xoxb-9436740570114-107427753' + '06003-OS2ZB9w4fj94eZ4dh5gUP19l',
  SLACK_CHANNEL: 'C0AN1KJNXUJ',
  SQL_WEBHOOK: 'https://lokokk2002ai.zeabur.app/webhook/supabase-sql',
  SITE_URL: 'https://viral-benchmark.zeabur.app',
  GEMINI_MODEL: 'gemini-2.5-flash',
};

// 把 items + CONFIG 傳下去
const items = $input.first().json.body?.items || $input.first().json.items || [];
return items.map(item => ({ json: { ...item, _config: CONFIG } }));

// =============================================
// 完整逐字稿生成流程（單項）
// =============================================

const item = $input.first().json;
const { queue_item_id, platform, video_id, video_url, title, author_name, _config: C } = item;

async function runSQL(sql) {
  const res = await fetch(C.SQL_WEBHOOK, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ sql }),
  });
  return res.json();
}

async function updateStatus(status, scriptRaw = null, timecodes = null) {
  const sets = [`status = '${status}'`];
  if (scriptRaw !== null) {
    sets.push(`script_raw = '${scriptRaw.replace(/'/g, "''")}'`);
  }
  if (timecodes !== null) {
    sets.push(`script_timecodes = '${JSON.stringify(timecodes).replace(/'/g, "''")}'::jsonb`);
  }
  if (status === 'completed') {
    sets.push(`script_generated_at = NOW()`);
  }
  await runSQL(`UPDATE viral_benchmark.shoot_queue SET ${sets.join(', ')} WHERE id = '${queue_item_id}'`);
}

try {
  // Step 1: TikHub 取得無水印下載 URL
  let downloadUrl = null;
  if (platform === 'douyin' || platform === 'tiktok') {
    const apiPath = platform === 'douyin'
      ? '/api/v1/douyin/app/v3/fetch_one_video'
      : '/api/v1/tiktok/app/v3/fetch_one_video';
    const tikRes = await fetch(
      `${C.TIKHUB_BASE}${apiPath}?aweme_id=${video_id}`,
      { headers: { Authorization: `Bearer ${C.TIKHUB_KEY}`, Accept: 'application/json' } }
    );
    if (tikRes.ok) {
      const tikJson = await tikRes.json();
      if (tikJson.code === 200) {
        const aweme = tikJson.data?.aweme_detail || tikJson.data;
        downloadUrl = aweme?.video?.play_addr?.url_list?.[0] || aweme?.video?.play_addr_h264?.url_list?.[0] || aweme?.video?.play_addr_lowbr?.url_list?.[0] || aweme?.video?.download_addr?.url_list?.[0] || null;
      }
    }
  }
  if (!downloadUrl) {
    const pn = platform === 'xiaohongshu' ? '小紅書' : platform === 'douyin' ? '抖音' : platform === 'tiktok' ? 'TikTok' : platform;
    const errMsg = `無法取得影片下載連結（${pn}）`;
    await updateStatus('failed', errMsg);
    return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'failed', error: errMsg, _config: C } }];
  }

  // Step 2: 下載影片
  const videoRes = await fetch(downloadUrl, {
    headers: { 'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36', Referer: 'https://www.douyin.com/' },
    redirect: 'follow',
  });
  if (!videoRes.ok) {
    const errMsg = '影片下載失敗，URL 可能已過期';
    await updateStatus('failed', errMsg);
    return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'failed', error: errMsg, _config: C } }];
  }
  const videoBuffer = await videoRes.arrayBuffer();
  const contentType = videoRes.headers.get('content-type') || 'video/mp4';
  const mimeType = contentType.includes('video') ? contentType : 'video/mp4';
  if (videoBuffer.byteLength < 10240) {
    const errMsg = '下載的影片檔案太小（< 10KB）';
    await updateStatus('failed', errMsg);
    return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'failed', error: errMsg, _config: C } }];
  }

  // Step 3: Gemini Files API 上傳
  const numBytes = videoBuffer.byteLength;
  const startRes = await fetch(
    `https://generativelanguage.googleapis.com/upload/v1beta/files?key=${C.GEMINI_KEY}`,
    {
      method: 'POST',
      headers: {
        'X-Goog-Upload-Protocol': 'resumable', 'X-Goog-Upload-Command': 'start',
        'X-Goog-Upload-Header-Content-Length': String(numBytes),
        'X-Goog-Upload-Header-Content-Type': mimeType, 'Content-Type': 'application/json',
      },
      body: JSON.stringify({ file: { display_name: `viral_${platform}_${video_id}` } }),
    }
  );
  if (!startRes.ok) {
    const errMsg = `Gemini 上傳啟動失敗: ${startRes.status}`;
    await updateStatus('failed', errMsg);
    return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'failed', error: errMsg, _config: C } }];
  }
  const uploadUrl = startRes.headers.get('x-goog-upload-url');
  if (!uploadUrl) {
    await updateStatus('failed', 'Gemini: 缺少 upload URL');
    return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'failed', error: 'Missing upload URL', _config: C } }];
  }
  const uploadRes = await fetch(uploadUrl, {
    method: 'POST',
    headers: { 'X-Goog-Upload-Command': 'upload, finalize', 'X-Goog-Upload-Offset': '0', 'Content-Length': String(numBytes) },
    body: videoBuffer,
  });
  if (!uploadRes.ok) {
    const errMsg = `Gemini 上傳失敗: ${uploadRes.status}`;
    await updateStatus('failed', errMsg);
    return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'failed', error: errMsg, _config: C } }];
  }
  const uploadJson = await uploadRes.json();
  const fileUri = uploadJson?.file?.uri;
  const fileName = uploadJson?.file?.name;
  if (!fileUri || !fileName) {
    await updateStatus('failed', 'Gemini: 缺少 file URI');
    return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'failed', error: 'Missing file URI', _config: C } }];
  }

  // Step 3c: 等待影片處理完成
  let fileReady = false;
  for (let i = 0; i < 30; i++) {
    await new Promise(r => setTimeout(r, 3000));
    const sRes = await fetch(`https://generativelanguage.googleapis.com/v1beta/${fileName}?key=${C.GEMINI_KEY}`);
    if (!sRes.ok) continue;
    const sJson = await sRes.json();
    if (sJson.state === 'ACTIVE') { fileReady = true; break; }
    if (sJson.state === 'FAILED') {
      await updateStatus('failed', 'Gemini 影片處理失敗');
      return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'failed', error: 'Gemini file processing failed', _config: C } }];
    }
  }
  if (!fileReady) {
    await updateStatus('failed', 'Gemini 影片處理超時（90秒）');
    return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'failed', error: 'Gemini timeout', _config: C } }];
  }

  // Step 4: Gemini 多模態生成逐字稿
  const PROMPT = '你是一位專業的影片逐字稿轉錄員。\n\n## 任務\n請仔細觀看並聆聽這支影片，產出 **1:1 完全還原** 的逐字稿。\n\n## 嚴格要求\n1. **dialogue 欄位必須是影片中實際說出的每一句話**，一字不漏、一字不改、不要潤飾、不要改寫、不要摘要\n2. 如果影片中有背景音樂但沒有人說話，dialogue 填「（無對話）」\n3. 如果影片中有畫面文字（字卡、字幕），在 scene 中完整記錄\n4. scene 欄位描述你「實際看到的畫面」，不是你推測的\n5. note 欄位記錄該片段的拍攝手法或特殊效果（轉場、濾鏡、特效文字等）\n6. **必須使用繁體中文輸出**（即使原始影片是簡體中文或其他語言，也要轉為繁體中文）\n7. 時間碼必須精準對應影片的實際時間軸\n\n## 輸出格式\n直接輸出 JSON 陣列，不要用 markdown code block 包裝，不要加任何說明文字：\n[{"timecode": "00:00-00:03", "scene": "畫面", "dialogue": "對話", "note": "備註"}]';
  const geminiRes = await fetch(
    `https://generativelanguage.googleapis.com/v1beta/models/${C.GEMINI_MODEL}:generateContent?key=${C.GEMINI_KEY}`,
    {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        contents: [{ parts: [{ file_data: { mime_type: mimeType, file_uri: fileUri } }, { text: PROMPT }] }],
        generationConfig: { temperature: 0.2, maxOutputTokens: 8192 },
      }),
    }
  );
  if (!geminiRes.ok) {
    const errMsg = `Gemini API 錯誤: ${geminiRes.status}`;
    await updateStatus('failed', errMsg);
    return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'failed', error: errMsg, _config: C } }];
  }
  const geminiJson = await geminiRes.json();
  const raw = geminiJson.candidates?.[0]?.content?.parts?.[0]?.text || '';
  if (!raw) {
    await updateStatus('failed', 'Gemini 回傳空白');
    return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'failed', error: 'Empty response', _config: C } }];
  }

  // Step 5: 解析
  let timecodes = [];
  try { const m = raw.match(/\[[\s\S]*\]/); if (m) timecodes = JSON.parse(m[0]); } catch {}
  if (!timecodes.length) { try { const m = raw.match(/```(?:json)?\s*([\s\S]*?)```/); if (m) timecodes = JSON.parse(m[1].trim()); } catch {} }
  if (Array.isArray(timecodes) && timecodes.length > 0) {
    timecodes = timecodes.map(tc => ({ timecode: tc.timecode||tc.time||'', scene: tc.scene||tc.visual||tc.description||'', dialogue: tc.dialogue||tc.script||tc.text||'', note: tc.note||tc.remark||'' }));
  }
  if (!timecodes.length) {
    await updateStatus('failed', `無法解析逐字稿。原始: ${raw.substring(0, 500)}`);
    return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'failed', error: '無法解析逐字稿', _config: C } }];
  }

  // Step 6: 寫回 DB
  await updateStatus('completed', raw, timecodes);
  return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'completed', timecodes_count: timecodes.length, _config: C } }];

} catch (err) {
  const errorMsg = err.message || String(err);
  try { await updateStatus('failed', `處理錯誤: ${errorMsg.substring(0, 500)}`); } catch {}
  return [{ json: { queue_item_id, title: title || '未知影片', platform: platform || '', status: 'failed', error: errorMsg.substring(0, 200), _config: C } }];
}

// 匯總結果 + Slack 通知
const results = $input.all().map(i => i.json);
const C = results[0]?._config || {};
const completed = results.filter(r => r.status === 'completed');
const failed = results.filter(r => r.status === 'failed');
const total = results.length;

let blocks = [];
if (failed.length === 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*✅ 逐字稿生成完成*\n共 ${total} 支全部成功` } });
} else if (completed.length === 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*⚠️ 逐字稿生成失敗*\n共 ${total} 支全部失敗` } });
} else {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*📝 逐字稿生成結果*\n成功 ${completed.length} 支，失敗 ${failed.length} 支（共 ${total} 支）` } });
}
if (completed.length > 0) {
  const list = completed.map(r => {
    const e = r.platform === 'douyin' ? '🎵' : r.platform === 'tiktok' ? '📱' : '📕';
    return `${e} ${(r.title||'').substring(0,30)||'未知影片'}（${r.timecodes_count||0} 段）`;
  }).join('\n');
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*成功：*\n${list}` } });
}
if (failed.length > 0) {
  const list = failed.map(r => {
    const e = r.platform === 'douyin' ? '🎵' : r.platform === 'tiktok' ? '📱' : '📕';
    return `${e} ${(r.title||'').substring(0,30)||'未知影片'}\n   └ 原因：${(r.error||'未知錯誤').substring(0,60)}`;
  }).join('\n');
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*失敗：*\n${list}` } });
}
blocks.push({ type: 'divider' });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `👉 <${C.SITE_URL || 'https://viral-benchmark.zeabur.app'}/shoot-queue|前往拍攝佇列查看>` } });

if (C.SLACK_TOKEN && C.SLACK_CHANNEL) {
  try {
    await fetch('https://slack.com/api/chat.postMessage', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${C.SLACK_TOKEN}` },
      body: JSON.stringify({ channel: C.SLACK_CHANNEL, blocks, text: `逐字稿生成結果：成功 ${completed.length}，失敗 ${failed.length}` }),
    });
  } catch {}
}

return [{ json: { total, completed: completed.length, failed: failed.length, results } }];
